import time

_cache = {}

def set_cache(key, value, ttl=60):
    _cache[key] = {'value': value, 'expires_at': time.time() + ttl}

def get_cache(key):
    if key in _cache:
        entry = _cache[key]
        if time.time() < entry['expires_at']:
            return entry['value']
        del _cache[key]
    return None

