solution.auth.py:
import hashlib
import secrets
import string
from datetime import datetime, timedelta

sessions = {}
SESSION_TTL_MINUTES = 30

def hash_password(password):
    return hashlib.sha256(password.encode()).hexdigest()

def generate_token():
    return secrets.token_hex(32)

def login(username, password_hash):
    token = generate_token()
    sessions[token] = {'user': username, 'created_at': datetime.now()}
    return token

def is_authenticated(token):
    if token not in sessions:
        return False
    created_at = sessions[token]['created_at']
    if datetime.now() - created_at > timedelta(minutes=SESSION_TTL_MINUTES):
        del sessions[token]
        return False
    return True

def logout(token):
    if token in sessions:
        del sessions[token]

